// === READ RESUME FROM PDF ===
const resumeText = $input.first().json.text;

if (!resumeText || resumeText.trim().length < 50) {
  throw new Error('Resume PDF appears empty or too short. Make sure you placed a valid PDF resume in the resumes/ folder.');
}

// === EDIT THESE SETTINGS ===
const baseConfig = {
  minScore: 50,
  maxResults: 25,
  yourEmail: 'YOUR_EMAIL@gmail.com',
  spreadsheetId: 'YOUR_GOOGLE_SHEET_ID',
  geminiApiKey: 'YOUR_GEMINI_API_KEY',
  serpApiKey: 'YOUR_SERPAPI_KEY',
  resumeText: resumeText.trim()
};

const roles = '"Backend Developer" OR "Senior Backend Developer" OR ".NET Developer" OR "Full Stack Developer" OR "Software Engineer 2" OR "SDE 2" OR "Senior Software Engineer" OR "Senior Full Stack Developer" OR "C# Developer" OR "ASP.NET Developer" OR "Software Engineer" OR "Backend Engineer" OR "Application Developer" OR "Software Developer" OR "AI Platform Engineer" OR "Backend Engineer AI" OR "Gen AI Engineer"';

// Two searches: Bangalore onsite/hybrid + India remote
return [
  { json: { ...baseConfig, searchQuery: roles + ' onsite OR hybrid', location: 'Bangalore, Karnataka, India' } },
  { json: { ...baseConfig, searchQuery: roles + ' remote', location: 'India' } }
];

const allItems = $input.all();
const config = $('Set Job Preferences').first().json;
let allJobs = [];

for (const item of allItems) {
  const jobs = item.json.jobs_results || [];
  const parsed = jobs.slice(0, config.maxResults || 20).map(job => {
    const raw = (job.company_name || '') + '|' + (job.title || '');
    let hash = 0;
    for (let i = 0; i < raw.length; i++) {
      const char = raw.charCodeAt(i);
      hash = ((hash << 5) - hash) + char;
      hash = hash & hash;
    }
    const jobId = 'JOB_' + Math.abs(hash).toString(36);

    let applyLink = '';
    if (job.apply_options && job.apply_options.length > 0) {
      applyLink = job.apply_options[0].link || '';
    } else if (job.share_link) {
      applyLink = job.share_link;
    }

    return {
      jobId,
      title: job.title || 'Unknown Title',
      company: job.company_name || 'Unknown Company',
      location: job.location || 'Not specified',
      description: (job.description || '').substring(0, 3000),
      postedDate: job.detected_extensions?.posted_at || 'Unknown',
      applyLink,
      source: job.via || 'Google Jobs',
      salary: job.detected_extensions?.salary || 'Not listed',
      schedule: job.detected_extensions?.schedule_type || ''
    };
  });
  allJobs.push(...parsed);
}

if (allJobs.length === 0) {
  throw new Error('No jobs found. Try broadening your search query or changing location.');
}

return { json: { jobs: allJobs, totalFound: allJobs.length } };

const data = $input.first().json;
const jobs = data.jobs || [];
return jobs.map(job => ({ json: job }));

// Gemini response: candidates[0].content.parts[0].text
const response = $input.item.json;
const aiResponse = response.candidates?.[0]?.content?.parts?.[0]?.text || '';
const jobData = $('Filter Duplicates').item;

let parsed;
try {
  parsed = JSON.parse(aiResponse);
} catch (e) {
  const jsonMatch = aiResponse.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    parsed = JSON.parse(jsonMatch[0]);
  } else {
    parsed = {
      score: 0,
      matchReason: 'Could not parse AI response',
      missingSkills: [],
      keyMatchingSkills: [],
      experienceFit: 'unknown',
      recommendation: 'skip'
    };
  }
}

return {
  json: {
    ...jobData.json,
    score: parsed.score || 0,
    matchReason: parsed.matchReason || '',
    missingSkills: parsed.missingSkills || [],
    keyMatchingSkills: parsed.keyMatchingSkills || [],
    experienceFit: parsed.experienceFit || 'unknown',
    recommendation: parsed.recommendation || 'skip'
  }
};

const items = $input.all();
const minScore = $('Set Job Preferences').first().json.minScore || 70;

const matched = items.filter(item => (item.json.score || 0) >= minScore);

if (matched.length === 0) {
  throw new Error(`No jobs scored above ${minScore}. Top score was ${Math.max(...items.map(i => i.json.score || 0))}. Try lowering minScore in Set Job Preferences.`);
}

return matched;

const jobData = $('Filter Top Matches').item;
const response = $input.item.json;
const coverLetter = response.candidates?.[0]?.content?.parts?.[0]?.text || 'Cover letter generation failed.';

return {
  json: {
    ...jobData.json,
    coverLetter: coverLetter.trim(),
    processedDate: new Date().toISOString().split('T')[0]
  }
};

const items = $input.all();
const config = $('Set Job Preferences').first().json;
const today = new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

if (items.length === 0) {
  return {
    json: {
      subject: `Job Search: No new matches found - ${today}`,
      htmlBody: `<html><body style="font-family: Arial, sans-serif;"><h2>Job Search Report - ${today}</h2><p>No new jobs matched your criteria (minimum score: ${config.minScore}).</p><p>Try broadening your search query or lowering the minimum score.</p></body></html>`,
      matchCount: 0,
      topScore: 0,
      yourEmail: config.yourEmail
    }
  };
}

const sorted = items.map(i => i.json).sort((a, b) => (b.score || 0) - (a.score || 0));
const topScore = sorted[0]?.score || 0;

let jobRows = sorted.map((j, i) => {
  const title = j['Job Title'] || j.title || 'Unknown Title';
  const company = j['Company'] || j.company || 'Unknown';
  const location = j['Location'] || j.location || 'Not specified';
  const score = j['Match Score'] || j.score || 0;
  const recommendation = j['Recommendation'] || j.recommendation || 'skip';
  const matchReason = j['Match Reason'] || j.matchReason || '';
  const missingSkills = j['Missing Skills'] || (j.missingSkills ? (Array.isArray(j.missingSkills) ? j.missingSkills.join(', ') : j.missingSkills) : '');
  const applyLink = j['Apply Link'] || j.applyLink || '#';
  const coverLetter = j['Cover Letter'] || j.coverLetter || '';
  const source = j.source || 'Google Jobs';
  const salary = j.salary || 'Not listed';

  const scoreColor = score >= 85 ? '#27ae60' : score >= 70 ? '#f39c12' : '#e74c3c';
  const recBadge = recommendation === 'strong-apply' ? 'Strong Apply' :
                   recommendation === 'apply' ? 'Apply' :
                   recommendation === 'maybe' ? 'Maybe' : 'Skip';

  return `
    <tr style="border-bottom: 1px solid #eee;">
      <td style="padding: 12px;">
        <strong>${title}</strong><br>
        <span style="color: #666;">${company} - ${location}</span><br>
        <span style="color: #888; font-size: 12px;">${source} | ${salary}</span>
      </td>
      <td style="padding: 12px; text-align: center;">
        <span style="background: ${scoreColor}; color: white; padding: 4px 12px; border-radius: 12px; font-weight: bold;">${score}</span>
      </td>
      <td style="padding: 12px; text-align: center;">${recBadge}</td>
      <td style="padding: 12px;">
        <a href="${applyLink}" style="background: #3498db; color: white; padding: 8px 16px; border-radius: 4px; text-decoration: none; display: inline-block;">Apply</a>
      </td>
    </tr>
    <tr>
      <td colspan="4" style="padding: 8px 12px; background: #f9f9f9;">
        <strong>Why it matches:</strong> ${matchReason}<br>
        ${missingSkills ? '<strong>Missing:</strong> ' + missingSkills : ''}
      </td>
    </tr>
    <tr>
      <td colspan="4" style="padding: 8px 12px; background: #f0f7ff;">
        <details>
          <summary style="cursor: pointer; font-weight: bold;">Cover Letter (click to expand)</summary>
          <div style="white-space: pre-wrap; margin-top: 8px; padding: 12px; background: white; border: 1px solid #ddd; border-radius: 4px;">${coverLetter}</div>
        </details>
      </td>
    </tr>`;
}).join('');

const htmlBody = `
<html>
<body style="font-family: Arial, sans-serif; max-width: 800px; margin: 0 auto;">
  <div style="background: linear-gradient(135deg, #667eea 0%, #764ba2 100%); padding: 24px; border-radius: 8px 8px 0 0;">
    <h1 style="color: white; margin: 0;">Job Search Report</h1>
    <p style="color: rgba(255,255,255,0.8); margin: 8px 0 0;">${today}</p>
  </div>
  <div style="background: #f5f5f5; padding: 16px; display: flex; gap: 16px;">
    <div style="background: white; padding: 12px 24px; border-radius: 8px; text-align: center;">
      <div style="font-size: 24px; font-weight: bold; color: #3498db;">${sorted.length}</div>
      <div style="color: #888; font-size: 12px;">Matches Found</div>
    </div>
    <div style="background: white; padding: 12px 24px; border-radius: 8px; text-align: center;">
      <div style="font-size: 24px; font-weight: bold; color: #27ae60;">${topScore}</div>
      <div style="color: #888; font-size: 12px;">Top Score</div>
    </div>
  </div>
  <table style="width: 100%; border-collapse: collapse; background: white;">
    <thead>
      <tr style="background: #ecf0f1;">
        <th style="padding: 12px; text-align: left;">Job</th>
        <th style="padding: 12px; text-align: center;">Score</th>
        <th style="padding: 12px; text-align: center;">Action</th>
        <th style="padding: 12px;">Link</th>
      </tr>
    </thead>
    <tbody>
      ${jobRows}
    </tbody>
  </table>
  <div style="padding: 16px; text-align: center; color: #888; font-size: 12px;">
    Generated by n8n Job Search Automation | Min score: ${config.minScore}
  </div>
</body>
</html>`;

return {
  json: {
    subject: `${sorted.length} Job Matches (Top: ${topScore}/100) - ${new Date().toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}`,
    htmlBody,
    matchCount: sorted.length,
    topScore,
    yourEmail: config.yourEmail
  }
};

const emailData = $input.first().json;

return {
  json: {
    success: true,
    message: 'Job search automation completed!',
    matchCount: emailData.matchCount || 0,
    topScore: emailData.topScore || 0,
    emailSent: true,
    sentTo: emailData.yourEmail || 'unknown',
    timestamp: new Date().toISOString()
  }
};
